ck_1782453397668_2h576_20260626085651_fd7032.pdf", "fileName": "Инструкция по работе Участника.pdf", "_path": [18, 1], "_pathStr": "18.1"}, {"id": "block_1782453398044_vbbhk", "type": "file", "title": "Инструкция по работе Заказчика", "file": "uploads/files/knowledge_block_file_block_1782453398044_vbbhk_20260626085700_fbc1dd.pdf", "fileName": "Инструкция по работе Заказчика.pdf", "_path": [18, 2], "_pathStr": "18.2"}], "_path": [18], "_pathStr": "18"}, {"id": "block_1782453436580_o6h8r", "type": "group", "value": "Бланки и шаблоны ЭТП", "defaultExpanded": false, "children": [{"id": "block_1782453450075_ssgpf", "type": "file", "title": "Бланк доверенности на Представителя, включаемого в личный кабинет", "file": "uploads/files/knowledge_block_file_block_1782453450075_ssgpf_20260626085941_0ec582.docx", "fileName": "Бланк доверенности на Представителя, включаемого в личный кабинет.docx", "_path": [19, 0], "_pathStr": "19.0"}, {"id": "block_1782453450299_ycv9l", "type": "file", "title": "Бланк заявления на запрос логина Представителя", "file": "uploads/files/knowledge_block_file_block_1782453450299_ycv9l_20260626085950_3ca08b.docx", "fileName": "Бланк заявления на запрос логина Представителя..docx", "_path": [19, 1], "_pathStr": "19.1"}, {"id": "block_1782453450516_exukj", "type": "file", "title": "Бланк заявления на включение Представителя в личный кабинет", "file": "uploads/files/knowledge_block_file_block_1782453450516_exukj_20260626085958_dc761e.docx", "fileName": "Бланк заявления на включение Представителя в личный кабинет..docx", "_path": [19, 2], "_pathStr": "19.2"}, {"id": "block_1782453450939_z7747", "type": "file", "title": "Бланк перечня используемых Заказчиком способов закупок и протоколов", "file": "uploads/files/knowledge_block_file_block_1782453450939_z7747_20260626090010_232214.docx", "fileName": "Бланк перечня используемых Заказчиком способов закупок и протоколов..docx", "_path": [19, 3], "_pathStr": "19.3"}], "_path": [19], "_pathStr": "19"}]}, "crzrt_news_page_data": {"hero": {"background": "uploads/landing/news_hero_bg_20260625114403_06f764.webp", "title": "Новости", "titleColor": "#ffffff", "titleTop": 234, "titleLeft": 60, "titleFontSize": "", "titleFontWeight": "", "titleItalic": false, "titleUnderline": false, "subtitle": "", "subtitleColor": "#FFFFFF", "subtitleTop": 213, "subtitleLeft": 70, "subtitleFontSize": "", "subtitleFontWeight": "", "subtitleItalic": false, "subtitleUnderline": false}, "items": [{"id": "news_1784034273945", "image": "uploads/landing/news_item_image_0_20260714160510_c31d9b.webp", "title": "Минфин разъяснил нюанс оплаты бумажных контрактов по итогам закупок малого объема с 1 июля 2026 года", "date": "2026-07-11", "text": "<p>Оплата контрактов с единственным поставщиком, которые заключаются по результатам <a href=\"https://login.consultant.ru/link/?req=doc&amp;base=CJI&amp;n=114700&amp;dst=100006&amp;demo=1\" data-link-type=\"cons-doc\">закупок малого объема</a> без использования ЕИС, <a href=\"https://login.consultant.ru/link/?req=doc&amp;base=QUEST&amp;n=237331&amp;dst=100011&amp;demo=1\" data-link-type=\"cons-doc\">не противоречит</a> Закону N 44-ФЗ.</p><p>Вывод касается нецифровых контрактов, сведения о которых до 1 мая 2028 года <a href=\"https://login.consultant.ru/link/?req=doc&amp;base=LAW&amp;n=524118&amp;dst=342&amp;demo=1\" data-link-type=\"cons-doc\">можно передавать</a> в реестр в упрощенном порядке в виде перечня заключенных сделок с кратким набором данных.</p><p><span style=\"font-size: 15.2px;\">Источник: Консультан.Плюс Новости https://www.consultant.ru/legalnews/32042/</span></p><p><br></p>", "active": true}, {"id": "news_1784034235785", "image": "uploads/landing/news_item_image_1_20260714160436_8da73a.webp", "title": "Изменять условия федеральных контрактов на ремонт и содержание дорог из-за роста НДС можно с 17 июля", "date": "2026-07-10", "text": "<div class=\"news-page__content\"><div class=\"news-page__text\"><p>С 17 июля 2026 года в случаях, когда контракт на ремонт и содержание автодорог общего пользования федерального значения невозможно исполнить из-за увеличения ставки НДС, сторонам <a href=\"https://login.consultant.ru/link/?req=doc&amp;base=LAW&amp;n=539079&amp;dst=100005&amp;demo=1\" data-link-type=\"cons-doc\">разрешат</a>:</p><ul><li><a href=\"https://login.consultant.ru/link/?req=doc&amp;base=LAW&amp;n=539079&amp;dst=100006&amp;demo=1\" data-link-type=\"cons-doc\">изменить</a> цену в пределах увеличения ставки налога (в части товаров, работ и услуг, приемка которых проводится после 1 января 2026 года);</li><li><a href=\"https://login.consultant.ru/link/?req=doc&amp;base=LAW&amp;n=539079&amp;dst=100007&amp;demo=1\" data-link-type=\"cons-doc\">скорректировать</a> объемы и виды работ и стройресурсов без увеличения цены.</li></ul><p>Новшество <a href=\"https://login.consultant.ru/link/?req=doc&amp;base=LAW&amp;n=539079&amp;dst=100008&amp;demo=1\" data-link-type=\"cons-doc\">коснется</a> федеральных контрактов, которые заключили до 1 января 2026 года (либо по итогам закупок, которые были объявлены до этой даты) без учета новой ставки НДС.</p><p>Регионам и муниципалитетам <a href=\"https://login.consultant.ru/link/?req=doc&amp;base=LAW&amp;n=539079&amp;dst=100009&amp;demo=1\" data-link-type=\"cons-doc\">рекомендовано утвердить</a> аналогичные правила для контрактов своего уровня.</p></div></div><div class=\"news-page__bottom\"><div class=\"news-page__attachments\"><div class=\"attachments attachments_docs\"><div class=\"attachments__title\"><br></div><div class=\"attachments__title\"><span style=\"font-size: 15.2px;\">Источник: Консультан.Плюс Новости&nbsp;https://www.consultant.ru/legalnews/32035/</span></div><div class=\"attachments__links\"><div class=\"attachments__item\"><br></div><div class=\"attachments__item\"><br></div></div></div></div></div>", "active": true}, {"id": "news_1784034168193", "image": "uploads/landing/news_item_image_2_20260714160436_d05ba7.webp", "title": "Юридически значимыми сообщениями можно будет обмениваться через Госуслуги – проект прошел Госдуму", "date": "2026-07-09", "text": "<div class=\"news-page__intro-thumb\"></div><div class=\"news-page__text\"><p>Планируют создать <a href=\"https://login.consultant.ru/link/?req=doc&amp;base=PRJ&amp;n=276241&amp;dst=100046&amp;demo=1\" data-link-type=\"cons-doc\">электронную почтовую систему</a>. Ее станут использовать, в частности, для приема и доставки заявлений, уведомлений, извещений, требований и прочих юридически значимых сообщений.</p><p>На <a href=\"https://www.gosuslugi.ru/\">Госуслугах</a> у компаний, ИП и других физлиц, которые зарегистрированы в <a href=\"https://login.consultant.ru/link/?req=doc&amp;base=CJI&amp;n=150030&amp;dst=100092&amp;demo=1\" data-link-type=\"cons-doc\">ЕСИА</a>, появятся <a href=\"https://login.consultant.ru/link/?req=doc&amp;base=PRJ&amp;n=276241&amp;dst=100064&amp;demo=1\" data-link-type=\"cons-doc\">электронные почтовые ящики</a>. Через них <a href=\"https://login.consultant.ru/link/?req=doc&amp;base=PRJ&amp;n=276241&amp;dst=100073&amp;demo=1\" data-link-type=\"cons-doc\">можно обмениваться</a> документами и сообщениями. В системе будет функция поиска адресатов. В ряде случаев юридически значимые сообщения, которые направляют по условиям сделки или НПА, <a href=\"https://login.consultant.ru/link/?req=doc&amp;base=PRJ&amp;n=276241&amp;dst=100065&amp;demo=1\" data-link-type=\"cons-doc\">станут приходить</a> в том числе на такие ящики.</p><p>По общим правилам за использование ящика <a href=\"https://login.consultant.ru/link/?req=doc&amp;base=PRJ&amp;n=276241&amp;dst=100075&amp;demo=1\" data-link-type=\"cons-doc\">надо будет платить</a>. Если этого не сделать, доступ к нему <a href=\"https://login.consultant.ru/link/?req=doc&amp;base=PRJ&amp;n=276241&amp;dst=100078&amp;demo=1\" data-link-type=\"cons-doc\">приостановят</a> до момента внесения денег. Правительство установит размер, порядок и сроки оплаты.</p><p>Основная часть рассмотренных поправок может вступить в силу <a href=\"https://login.consultant.ru/link/?req=doc&amp;base=PRJ&amp;n=276241&amp;dst=100167&amp;demo=1\" data-link-type=\"cons-doc\">с 1 сентября 2027 года</a>.</p><p><br></p><p><span style=\"font-size: 15.2px;\">Источник: Консультан.Плюс Новости https://www.consultant.ru/legalnews/32025/</span></p></div>", "active": true}, {"id": "news_1784034140329", "image": "", "title": "Для шприцев-манометров действует защитная мера в виде преимущества – ВС РФ отказал в пересмотре дела", "date": "2026-07-09", "text": "<div class=\"news-page__intro-thumb\"></div><div class=\"news-page__text\"><p>Заказчик <a href=\"https://login.consultant.ru/link/?req=doc&amp;base=AMS&amp;n=576618&amp;dst=100049&amp;demo=1\" data-link-type=\"cons-doc\">приобретал</a> медицинские расходники, в том числе шприцы-манометры для баллонного катетера с кодом <a href=\"https://login.consultant.ru/link/?req=doc&amp;base=LAW&amp;n=538129&amp;dst=125817&amp;demo=1\" data-link-type=\"cons-doc\">32.50.13.110</a> по ОКПД 2. В извещении он установил для них защитную меру в виде преимущества. Контролеры решили, что такой товар относится к позиции <a href=\"https://login.consultant.ru/link/?req=doc&amp;base=LAW&amp;n=538613&amp;dst=101901&amp;demo=1\" data-link-type=\"cons-doc\">385</a> перечня N 2 – хирургические иглы, колющие инструменты, шприцы. На эту продукцию распространяется ограничение.</p><p>Суды трех инстанций <a href=\"https://login.consultant.ru/link/?req=doc&amp;base=AMS&amp;n=576618&amp;dst=100071&amp;demo=1\" data-link-type=\"cons-doc\">не поддержали</a> контролеров:</p><ul><li>одна из основных функций шприца-манометра – <a href=\"https://login.consultant.ru/link/?req=doc&amp;base=AMS&amp;n=576618&amp;dst=100054&amp;demo=1\" data-link-type=\"cons-doc\">создание</a> или снятие давления в хирургическом изделии во время процедуры. Его <a href=\"https://login.consultant.ru/link/?req=doc&amp;base=AMS&amp;n=576618&amp;dst=100055&amp;demo=1\" data-link-type=\"cons-doc\">не используют</a> для пункции, в комплекте нет иглы. Эту продукцию <a href=\"https://login.consultant.ru/link/?req=doc&amp;base=AMS&amp;n=576618&amp;dst=100059&amp;demo=1\" data-link-type=\"cons-doc\">нельзя отнести</a> к шприцам общего назначения – у товаров разные конструкции и назначение;</li><li>хотя объект закупки и соответствует коду <a href=\"https://login.consultant.ru/link/?req=doc&amp;base=LAW&amp;n=538129&amp;dst=125817&amp;demo=1\" data-link-type=\"cons-doc\">32.50.13.110</a> по ОКПД 2, который входит в позицию <a href=\"https://login.consultant.ru/link/?req=doc&amp;base=LAW&amp;n=538613&amp;dst=101901&amp;demo=1\" data-link-type=\"cons-doc\">385</a> перечня N 2, но он <a href=\"https://login.consultant.ru/link/?req=doc&amp;base=AMS&amp;n=576618&amp;dst=100061&amp;demo=1\" data-link-type=\"cons-doc\">не отвечает</a> указанному в ней наименованию товара. Преимущество <a href=\"https://login.consultant.ru/link/?req=doc&amp;base=AMS&amp;n=576618&amp;dst=100067&amp;demo=1\" data-link-type=\"cons-doc\">установили</a> верно.</li></ul><p>ВС РФ <a href=\"https://login.consultant.ru/link/?req=doc&amp;base=ARB&amp;n=891883&amp;dst=100016&amp;demo=1\" data-link-type=\"cons-doc\">не стал</a> пересматривать дело.</p><p>💡 В практике можно встретить примеры как со <a href=\"https://login.consultant.ru/link/?req=doc&amp;base=RAPS013&amp;n=493269&amp;dst=100072&amp;demo=1\" data-link-type=\"cons-doc\">сходной</a>, так и с <a href=\"https://login.consultant.ru/link/?req=doc&amp;base=MARB&amp;n=3046702&amp;dst=100054&amp;demo=1\" data-link-type=\"cons-doc\">противоположной</a> позицией.</p><p><span style=\"font-size: 15.2px;\">Источник: Консультан.Плюс Новости&nbsp;https://www.consultant.ru/legalnews/32013/</span></p><p><br></p></div>", "active": true}, {"id": "news_1784034101321", "image": "", "title": "Правительство расширило перечень стратегически значимых лекарств", "date": "2026-07-08", "text": "<div class=\"news-page__intro-thumb\"></div><div class=\"news-page__text\"><p>В <a href=\"https://login.consultant.ru/link/?req=doc&amp;base=LAW&amp;n=532914&amp;dst=100010&amp;demo=1\" data-link-type=\"cons-doc\">список</a> стратегически значимых лекарств <a href=\"https://login.consultant.ru/link/?req=doc&amp;base=LAW&amp;n=538874&amp;dst=100006&amp;demo=1\" data-link-type=\"cons-doc\">добавили</a>, в частности, ЖНВЛП, препараты для лечения особо опасных инфекций, социально значимых и представляющих опасность для окружающих заболеваний.</p><p>В первый раздел <a href=\"https://login.consultant.ru/link/?req=doc&amp;base=LAW&amp;n=538874&amp;dst=100007&amp;demo=1\" data-link-type=\"cons-doc\">включили</a> 39 наименований. В их числе альбумин человека, декстроза, калия перманганат, лоразепам, магния сульфат, натрия хлорид, нитразепам.</p><p>Второй раздел <a href=\"https://login.consultant.ru/link/?req=doc&amp;base=LAW&amp;n=538874&amp;dst=100064&amp;demo=1\" data-link-type=\"cons-doc\">дополнили</a> 110 препаратами. Среди них появились акситиниб, венетоклакс, дроперидол, инсулин глулизин, нусинерсен, панкреатин, стрептомицин, тетрациклин, хлоргексидин, ципротерон.</p><p>💡 Напомним, <a href=\"https://login.consultant.ru/link/?req=doc&amp;base=LAW&amp;n=532914&amp;dst=100010&amp;demo=1\" data-link-type=\"cons-doc\">перечень</a> обновили в апреле, а <a href=\"https://login.consultant.ru/link/?req=doc&amp;base=LAW&amp;n=529586&amp;dst=100010&amp;demo=1\" data-link-type=\"cons-doc\">правила</a> и критерии его формирования правительство утвердило в марте 2026 года.</p><p><br></p><p><span style=\"font-size: 15.2px;\">Источник: Консультан.Плюс Новости&nbsp;https://www.consultant.ru/legalnews/32015/</span></p><p><br></p></div>", "active": true}, {"id": "news_1784034053329", "image": "uploads/landing/news_item_image_0_20260714160112_58b449.webp", "title": "Ошибки применения Закона N 44-ФЗ: обзор практики Московского УФАС за I квартал 2026 года", "date": "2026-07-08", "text": "<div class=\"news-page__intro-thumb\"></div><div class=\"news-page__intro\">Заказчики отказывались от заключения контракта из-за отзыва ЛБО, необоснованно закупали только оригинальные картриджи для принтера без возможности предложить эквивалент. Также они не направляли в РНП сведения о подрядчике, который не исполнил обязательства. Подробнее в обзоре.</div><div class=\"news-page__text\"><h2><strong>Отказ заказчика от заключения контракта из-за отзыва ЛБО</strong></h2><p>Заказчик <a href=\"https://login.consultant.ru/link/?req=doc&amp;base=CJI&amp;n=164620&amp;dst=100084&amp;demo=1\" data-link-type=\"cons-doc\">отказался</a> заключать контракт, а затем отменил закупку из-за отзыва ЛБО.</p><p><a href=\"https://login.consultant.ru/link/?req=doc&amp;base=CJI&amp;n=164620&amp;dst=100087&amp;demo=1\" data-link-type=\"cons-doc\">Контролеры</a> и <a href=\"https://login.consultant.ru/link/?req=doc&amp;base=CJI&amp;n=164620&amp;dst=100089&amp;demo=1\" data-link-type=\"cons-doc\">суды</a> с этим не согласились: в Законе N 44-ФЗ не предусмотрено право заказчика отказаться от подписания контракта либо отменить закупку по такой причине. Это обстоятельство не форс-мажор.</p><h2><strong>Необоснованная закупка оригинальных картриджей для принтера без возможности предложить эквивалент</strong></h2><p>В описании объекта закупки <a href=\"https://login.consultant.ru/link/?req=doc&amp;base=CJI&amp;n=164620&amp;dst=100096&amp;demo=1\" data-link-type=\"cons-doc\">установили</a> требование о поставке оригинальных картриджей для принтеров без возможности предложить эквивалент. Заказчик <a href=\"https://login.consultant.ru/link/?req=doc&amp;base=CJI&amp;n=164620&amp;dst=100098&amp;demo=1\" data-link-type=\"cons-doc\">пояснил</a>: оригинальные расходники были нужны, чтобы обеспечить совместимость с используемым оборудованием для его бесперебойной работы. Ранее из-за неоригинальных картриджей возникала техошибка.</p><p><a href=\"https://login.consultant.ru/link/?req=doc&amp;base=CJI&amp;n=164620&amp;dst=100100&amp;demo=1\" data-link-type=\"cons-doc\">Контролеры</a> и <a href=\"https://login.consultant.ru/link/?req=doc&amp;base=CJI&amp;n=164620&amp;dst=100106&amp;demo=1\" data-link-type=\"cons-doc\">суды</a> нашли нарушение:</p><ul><li>в руководстве по эксплуатации оборудования <a href=\"https://login.consultant.ru/link/?req=doc&amp;base=CJI&amp;n=164620&amp;dst=100101&amp;demo=1\" data-link-type=\"cons-doc\">нет</a> запрета на использование эквивалентных расходников;</li><li>производитель оборудования в письме лишь рекомендовал применять оригинальные расходники. Это не означает, что нельзя использовать аналоги;</li><li>заказчик <a href=\"https://login.consultant.ru/link/?req=doc&amp;base=CJI&amp;n=164620&amp;dst=100103&amp;demo=1\" data-link-type=\"cons-doc\">не доказал</a>, что применение неоригинальных расходников повлечет утрату гарантийного обслуживания оборудования;</li><li>ошибки при использовании совместимых картриджей <a href=\"https://login.consultant.ru/link/?req=doc&amp;base=CJI&amp;n=164620&amp;dst=100104&amp;demo=1\" data-link-type=\"cons-doc\">могли быть связаны</a> с иными техническими особенностями или неисправностями оборудования заказчика.</li></ul><h2><strong>Ненаправление в РНП сведений о подрядчике, который не исполнил обязательства</strong></h2><p>Подрядчик не приступил к исполнению контракта. По истечении его срока заказчик <a href=\"https://login.consultant.ru/link/?req=doc&amp;base=CJI&amp;n=164620&amp;dst=100149&amp;demo=1\" data-link-type=\"cons-doc\">разместил</a> в ЕИС акт о неисполнении обязательств, но сведения о контрагенте в РНП <a href=\"https://login.consultant.ru/link/?req=doc&amp;base=CJI&amp;n=164620&amp;dst=100150&amp;demo=1\" data-link-type=\"cons-doc\">не направил</a>.</p><p><a href=\"https://login.consultant.ru/link/?req=doc&amp;base=CJI&amp;n=164620&amp;dst=100152&amp;demo=1\" data-link-type=\"cons-doc\">Контролеры</a> и <a href=\"https://login.consultant.ru/link/?req=doc&amp;base=CJI&amp;n=164620&amp;dst=100156&amp;demo=1\" data-link-type=\"cons-doc\">суды</a> отметили:</p><ul><li>размещение акта о неисполнении обязательств вместо решения об одностороннем отказе от исполнения контракта не означает, что данные о подрядчике не направляют в РНП. Иначе он избежит ответственности и будет дальше участвовать в закупках, что противоречит целям ведения реестра;</li><li>если подрядчик не исполнил обязательства, которые позже прекратились из-за истечения срока контракта (а не из-за одностороннего отказа), у заказчика есть повод направить обращение о включении сведений в РНП.</li><li><br></li></ul><div><span style=\"font-size: 15.2px;\">Источник: Консультан.Плюс Новости https://www.consultant.ru/legalnews/32010/</span></div></div>", "active": true}, {"id": "news_1784034016433", "image": "uploads/landing/news_item_image_1_20260714160112_5aad4e.webp", "title": "Правительство пересмотрело исключения из запрета закупок иностранных товаров с 3 июля 2026 года", "date": "2026-07-07", "text": "<div class=\"news-page__intro-thumb\"></div><div class=\"news-page__text\"><p>Заказчики <a href=\"https://login.consultant.ru/link/?req=doc&amp;base=LAW&amp;n=538584&amp;dst=100013&amp;demo=1\" data-link-type=\"cons-doc\">обязаны применять</a> запрет при приобретении тканей, одежды и обуви по позициям 1 - 7 <a href=\"https://login.consultant.ru/link/?req=doc&amp;base=LAW&amp;n=538613&amp;dst=100287&amp;demo=1\" data-link-type=\"cons-doc\">перечня N 1</a> из Постановления&nbsp;N&nbsp;1875 в том числе в таких случаях:</p><ul><li><a href=\"https://login.consultant.ru/link/?req=doc&amp;base=LAW&amp;n=538613&amp;dst=232&amp;demo=1\" data-link-type=\"cons-doc\">закупка</a> 1 единицы продукции, если НМЦК, НМЦД или цена контракта (договора) с единственным поставщиком не выше 300 тыс. руб.;</li><li><a href=\"https://login.consultant.ru/link/?req=doc&amp;base=LAW&amp;n=538613&amp;dst=29&amp;demo=1\" data-link-type=\"cons-doc\">закупка</a> товаров, когда НМЦК (НМЦД), МЗЦК (МЗЦД) или цена контракта (договора) с единственным поставщиком не более 1 млн руб. и цена каждого товара, которая использовалась при определении таких цен, не превышает 300 тыс. руб.;</li><li><a href=\"https://login.consultant.ru/link/?req=doc&amp;base=LAW&amp;n=538613&amp;dst=30&amp;demo=1\" data-link-type=\"cons-doc\">закупка</a> продукции, если цена единицы товара, которая учитывалась при определении НМЦК, НМЦД или цены контракта (договора) с единственным поставщиком, не более 300 тыс. руб., а произведение каждой единицы на их количество не превышает 1 млн руб.</li></ul><div><br></div><div><div><span style=\"font-size: 15.2px;\">Источник: Консультан.Плюс Новости&nbsp;https://www.consultant.ru/legalnews/31986/</span></div></div><div><br></div></div>", "active": true}, {"id": "news_1784033955537", "image": "uploads/landing/news_item_image_2_20260714160112_2273bd.webp", "title": "Ограничение мобильного интернета не оправдывает пропуск срока подписания госконтракта, решил суд", "date": "2026-07-06", "text": "<p>Победитель запроса котировок <a href=\"https://login.consultant.ru/link/?req=doc&amp;base=ASZ&amp;n=325821&amp;dst=100014&amp;demo=1\" data-link-type=\"cons-doc\">не подписал</a> контракт в срок из-за ограничения мобильного интернета, которое <a href=\"https://login.consultant.ru/link/?req=doc&amp;base=ASZ&amp;n=325821&amp;dst=100029&amp;demo=1\" data-link-type=\"cons-doc\">ввели</a> для обеспечения безопасности. Он подтвердил это скриншотами из региональных и федеральных СМИ. Сведения <a href=\"https://login.consultant.ru/link/?req=doc&amp;base=ASZ&amp;n=325821&amp;dst=100016&amp;demo=1\" data-link-type=\"cons-doc\">внесли</a> в РНП.</p><p>Суды <a href=\"https://login.consultant.ru/link/?req=doc&amp;base=ASZ&amp;n=325821&amp;dst=100019&amp;demo=1\" data-link-type=\"cons-doc\">апелляционной</a> и <a href=\"https://login.consultant.ru/link/?req=doc&amp;base=ASZ&amp;n=325821&amp;dst=100020&amp;demo=1\" data-link-type=\"cons-doc\">кассационной</a> инстанций согласились с решением контролеров:</p><ul><li>спорные обстоятельства <a href=\"https://login.consultant.ru/link/?req=doc&amp;base=RAPS013&amp;n=493413&amp;dst=100070&amp;demo=1\" data-link-type=\"cons-doc\">не указывают</a> на то, что победитель не мог подписать контракт. Он <a href=\"https://login.consultant.ru/link/?req=doc&amp;base=ASZ&amp;n=325821&amp;dst=100030&amp;demo=1\" data-link-type=\"cons-doc\">имел</a> иные каналы и способы связи для исполнения обязательств. Так, из представленных скриншотов следует, что кабельный интернет и сотовая связь работали штатно, а их недоступность <a href=\"https://login.consultant.ru/link/?req=doc&amp;base=RAPS013&amp;n=493413&amp;dst=100068&amp;demo=1\" data-link-type=\"cons-doc\">не доказали</a>;</li><li>победитель <a href=\"https://login.consultant.ru/link/?req=doc&amp;base=RAPS013&amp;n=493413&amp;dst=100071&amp;demo=1\" data-link-type=\"cons-doc\">снизил</a> цену на 99,92%. Значит, у него не было намерения исполнить контракт.</li></ul><p>💡 Отметим, Краснодарское УФАС <a href=\"https://login.consultant.ru/link/?req=doc&amp;base=PAS&amp;n=1142627&amp;dst=100038&amp;demo=1\" data-link-type=\"cons-doc\">не включило</a> в РНП данные о победителе закупки, который не подписал контракт из-за <a href=\"https://login.consultant.ru/link/?req=doc&amp;base=PAS&amp;n=1142627&amp;dst=100030&amp;demo=1\" data-link-type=\"cons-doc\">ограничения</a> мобильного интернета. Контролеры учли, что победитель незамедлительно <a href=\"https://login.consultant.ru/link/?req=doc&amp;base=PAS&amp;n=1142627&amp;dst=100031&amp;demo=1\" data-link-type=\"cons-doc\">уведомил</a> заказчика о ситуации и выразил готовность исполнить контракт.</p><p><span style=\"font-size: 15.2px;\">Источник: Консультан.Плюс Новости&nbsp;</span>https://www.consultant.ru/legalnews/31987/</p>", "active": true}, {"id": "news_1783431377991", "image": "", "title": "Суд увидел искусственное дробление единой сделки в нескольких похожих неконкурентных госзакупках", "date": "2026-07-03", "text": "<div class=\"news-page__intro-thumb\"></div><div class=\"news-page__text\"><p>Заказчик в 2025 году в течение нескольких дней <a href=\"https://login.consultant.ru/link/?req=doc&amp;base=AVS&amp;n=136529&amp;dst=100024&amp;demo=1\" data-link-type=\"cons-doc\">заключил</a> с одним и тем же единственным поставщиком контракты на поставку спортоборудования. Цена каждого из них не превышала <a href=\"https://login.consultant.ru/link/?req=doc&amp;base=AVS&amp;n=136529&amp;dst=100025&amp;demo=1\" data-link-type=\"cons-doc\">600 тыс. руб</a>. Товары приняли и оплатили на общую сумму более 4 млн руб. Прокурор <a href=\"https://login.consultant.ru/link/?req=doc&amp;base=AVS&amp;n=136529&amp;dst=100027&amp;demo=1\" data-link-type=\"cons-doc\">увидел</a> в этом искусственное дробление единой сделки и <a href=\"https://login.consultant.ru/link/?req=doc&amp;base=AVS&amp;n=136529&amp;dst=100011&amp;demo=1\" data-link-type=\"cons-doc\">потребовал признать</a> контракты недействительными.</p><p>Суды <a href=\"https://login.consultant.ru/link/?req=doc&amp;base=AVS&amp;n=136529&amp;dst=100029&amp;demo=1\" data-link-type=\"cons-doc\">апелляционной</a> и <a href=\"https://login.consultant.ru/link/?req=doc&amp;base=AVS&amp;n=136529&amp;dst=100030&amp;demo=1\" data-link-type=\"cons-doc\">кассационной</a> инстанций поддержали надзорный орган, признали контракты ничтожными и <a href=\"https://login.consultant.ru/link/?req=doc&amp;base=AVS&amp;n=136529&amp;dst=100049&amp;demo=1\" data-link-type=\"cons-doc\">применили</a> одностороннюю реституцию:</p><ul><li>контракты <a href=\"https://login.consultant.ru/link/?req=doc&amp;base=AVS&amp;n=136529&amp;dst=100040&amp;demo=1\" data-link-type=\"cons-doc\">заключили</a> с одним поставщиком в короткий период времени. Они <a href=\"https://login.consultant.ru/link/?req=doc&amp;base=RAPS004&amp;n=127464&amp;dst=100038&amp;demo=1\" data-link-type=\"cons-doc\">имели</a> идентичный срок действия, похожие сроки поставки и единую цель – оснащение спортшколы оборудованием;</li><li>поставленные товары <a href=\"https://login.consultant.ru/link/?req=doc&amp;base=AVS&amp;n=136529&amp;dst=100041&amp;demo=1\" data-link-type=\"cons-doc\">были</a> однородными – у них одинаковый код по ОКПД 2;</li><li>доказательств того, что ситуация для неконкурентной закупки была исключительной, <a href=\"https://login.consultant.ru/link/?req=doc&amp;base=AVS&amp;n=136529&amp;dst=100042&amp;demo=1\" data-link-type=\"cons-doc\">не представили</a>;</li><li>ссылку на <a href=\"https://login.consultant.ru/link/?req=doc&amp;base=LAW&amp;n=508812&amp;dst=12471&amp;demo=1\" data-link-type=\"cons-doc\">норму</a> Закона N 44-ФЗ, которая разрешает свободно проводить несколько малых закупок однородных или идентичных товаров (работ, услуг) у единственного поставщика, отклонили. Она вступила в силу с 2026 года, контракты же заключили в 2025 году. Норма <a href=\"https://login.consultant.ru/link/?req=doc&amp;base=AVS&amp;n=136529&amp;dst=100043&amp;demo=1\" data-link-type=\"cons-doc\">не распространяется</a> на ранее возникшие отношения.</li></ul><div><span style=\"font-size: 15.2px;\">Источник: Консультан.Плюс Новости&nbsp;https://www.consultant.ru/legalnews/31968/</span></div><ul><li><br></li></ul></div>", "active": true}, {"id": "news_1783431353967", "image": "", "title": "Санкции повлияли на срок поставки по госконтракту – суд не нашел оснований включить данные в РНП", "date": "2026-07-02", "text": "<p>Стороны <a href=\"https://login.consultant.ru/link/?req=doc&amp;base=AUR&amp;n=281176&amp;dst=100022&amp;demo=1\" data-link-type=\"cons-doc\">заключили</a> контракт на поставку шовного материала. Его <a href=\"https://login.consultant.ru/link/?req=doc&amp;base=AUR&amp;n=281176&amp;dst=100026&amp;demo=1\" data-link-type=\"cons-doc\">следовало исполнять</a> по заявкам заказчика.</p><p>Предприниматель <a href=\"https://login.consultant.ru/link/?req=doc&amp;base=AUR&amp;n=281176&amp;dst=100037&amp;demo=1\" data-link-type=\"cons-doc\">поставил</a> часть товара с просрочкой, а часть не поставил вовсе. Заказчик <a href=\"https://login.consultant.ru/link/?req=doc&amp;base=AUR&amp;n=281176&amp;dst=100040&amp;demo=1\" data-link-type=\"cons-doc\">решил</a> в одностороннем порядке отказаться от сделки. Контролеры <a href=\"https://login.consultant.ru/link/?req=doc&amp;base=AUR&amp;n=281176&amp;dst=100041&amp;demo=1\" data-link-type=\"cons-doc\">включили</a> сведения в РНП.</p><p>Суды трех инстанций <a href=\"https://login.consultant.ru/link/?req=doc&amp;base=AUR&amp;n=281176&amp;dst=100089&amp;demo=1\" data-link-type=\"cons-doc\">не согласились</a> с решением контролеров. Они учли, что в контракте <a href=\"https://login.consultant.ru/link/?req=doc&amp;base=AUR&amp;n=281176&amp;dst=100073&amp;demo=1\" data-link-type=\"cons-doc\">не определили</a> конкретное количество товара и сроки подачи заявок. Предприниматель же пытался выполнить <a href=\"https://login.consultant.ru/link/?req=doc&amp;base=AUR&amp;n=281176&amp;dst=100072&amp;demo=1\" data-link-type=\"cons-doc\">заявку</a> заказчика на поставку продукции почти на всю сумму контракта:</p><ul><li><a href=\"https://login.consultant.ru/link/?req=doc&amp;base=AUR&amp;n=281176&amp;dst=100075&amp;demo=1\" data-link-type=\"cons-doc\">заказал</a> у производителей товары в день направления заявки, часть из которых <a href=\"https://login.consultant.ru/link/?req=doc&amp;base=AUR&amp;n=281176&amp;dst=100077&amp;demo=1\" data-link-type=\"cons-doc\">поставили</a>, но с просрочкой;</li><li><a href=\"https://login.consultant.ru/link/?req=doc&amp;base=AUR&amp;n=281176&amp;dst=100078&amp;demo=1\" data-link-type=\"cons-doc\">направил</a> заказчику гарантийное письмо, в котором обещал поставить оставшуюся продукцию, как только ее доставят на склад предпринимателя. Однако производитель <a href=\"https://login.consultant.ru/link/?req=doc&amp;base=AUR&amp;n=281176&amp;dst=100081&amp;demo=1\" data-link-type=\"cons-doc\">сообщил</a>, что ее изготовление задерживается из-за отсутствия импортных комплектующих на фоне санкций;</li><li>уведомил заказчика об остатке шовного материала у себя на складе и предложил ему безвозмездно <a href=\"https://login.consultant.ru/link/?req=doc&amp;base=AUR&amp;n=281176&amp;dst=100079&amp;demo=1\" data-link-type=\"cons-doc\">выбрать</a> подходящий или <a href=\"https://login.consultant.ru/link/?req=doc&amp;base=AUR&amp;n=281176&amp;dst=100082&amp;demo=1\" data-link-type=\"cons-doc\">заменить</a> продукцию на аналогичную;</li><li>после одностороннего отказа продолжал взаимодействовать с производителем. По мере изготовления товара <a href=\"https://login.consultant.ru/link/?req=doc&amp;base=AUR&amp;n=281176&amp;dst=100086&amp;demo=1\" data-link-type=\"cons-doc\">поставлял</a> его заказчику и выполнил обязательства на 75%.</li></ul><div><span style=\"font-size: 15.2px;\">Источник: Консультан.Плюс Новости https://www.consultant.ru/legalnews/31964/</span></div>", "active": true}, {"id": "news_1783431326471", "image": "", "title": "Национальный режим: Минпромторг пояснил, какой код по ОКПД 2 выбирать при закупках картриджей", "date": "2026-06-30", "text": "<p>едомство <a href=\"https://login.consultant.ru/link/?req=doc&amp;base=LAW&amp;n=537424&amp;dst=100012&amp;demo=1\" data-link-type=\"cons-doc\">сообщило</a>, что картриджи для лазерных принтеров и многофункциональных печатающих устройств в КТРУ могут иметь разные коды по ОКПД 2.</p><p>Однако в реестре российской промпродукции эти товары <a href=\"https://login.consultant.ru/link/?req=doc&amp;base=LAW&amp;n=537424&amp;dst=100013&amp;demo=1\" data-link-type=\"cons-doc\">классифицируют</a> лишь кодом <a href=\"https://login.consultant.ru/link/?req=doc&amp;base=LAW&amp;n=538129&amp;dst=119295&amp;demo=1\" data-link-type=\"cons-doc\">26.20.40.120</a> по ОКПД 2, который <a href=\"https://login.consultant.ru/link/?req=doc&amp;base=LAW&amp;n=537424&amp;dst=100014&amp;demo=1\" data-link-type=\"cons-doc\">входит</a> в <a href=\"https://login.consultant.ru/link/?req=doc&amp;base=LAW&amp;n=524024&amp;dst=100744&amp;demo=1\" data-link-type=\"cons-doc\">перечень продукции N 2</a> с защитной мерой в виде ограничения.</p><p>Заказчикам следует применять этот код. Использование иного кода <a href=\"https://login.consultant.ru/link/?req=doc&amp;base=LAW&amp;n=537424&amp;dst=100015&amp;demo=1\" data-link-type=\"cons-doc\">приведет</a> к несоблюдению нацрежима.</p><p>💡 Отметим, 13-й ААС <a href=\"https://login.consultant.ru/link/?req=doc&amp;base=RAPS013&amp;n=493942&amp;dst=100057&amp;demo=1\" data-link-type=\"cons-doc\">поддержал</a> заказчика, который указанный код не выбрал.</p><p><span style=\"font-size: 15.2px;\">Источник: Консультан.Плюс Новости&nbsp;https://www.consultant.ru/legalnews/31929/</span></p><p><br></p>", "active": true}, {"id": "news_1783431294798", "image": "", "title": "Самые интересные новости для специалиста по закупкам за июнь", "date": "2026-06-29", "text": "<h2><strong>Изменения законодательства</strong></h2><p>С 12 июня 2026 года действуют поправки, по которым с 2027 года госзакупки некоторых лекарств, а также медизделий в рамках нацпроектов \"Продолжительная и активная жизнь\", \"Семья\" будут централизованы. Подробнее в нашей <a href=\"/legalnews/31815/\" data-link-type=\"news\" class=\"visited\">новости</a>.</p><p>С 1 июля 2026 года начнут проводить централизованные госзакупки медизделий для больных сахарным диабетом. Подробнее в нашей <a href=\"/legalnews/31841/\" data-link-type=\"news\" class=\"visited\">новости</a>.</p><p>С 1 июля 2026 года защитную меру в виде ограничения распространят на металлические канаты без электроизоляции. Подробнее в нашей <a href=\"/legalnews/31888/\" data-link-type=\"news\" class=\"visited\">новости</a>.</p><h2><strong>Разъяснения ведомств</strong></h2><p>Минфин рассказал, нужно ли в коммерческом предложении для расчета НМЦК при закупках с нацрежимом подтверждать страну товара. Подробнее в нашей <a href=\"/legalnews/31760/\" data-link-type=\"news\">новости</a>.</p><p>Также ведомство ответило на вопрос, применяется ли нацрежим при проведении конкурса на услуги обязательного аудита. Подробнее в нашей <a href=\"/legalnews/31810/\" data-link-type=\"news\">новости</a>.</p><p>ФАС разъяснила, можно ли в описании объекта госзакупки привести конкретный вид стерилизации медизделий. Подробнее в нашей <a href=\"/legalnews/31733/\" data-link-type=\"news\">новости</a>.</p><p>Также ФАС дала рекомендации о формировании документации для госзакупки лекарств по решению врачебной комиссии. Подробнее в нашей <a href=\"/legalnews/31851/\" data-link-type=\"news\" class=\"visited\">новости</a>.</p><p>Кроме того, антимонопольная служба отказалась от прежней позиции, согласно которой при закупках проектно-изыскательских работ заказчикам следует устанавливать требование к членству в СРО лишь в области архитектурно-строительного проектирования. Подробнее в нашей <a href=\"/legalnews/31704/\" data-link-type=\"news\">новости</a>.</p><p>Минстрой сообщил, что участник закупки проектных и изыскательских работ должен состоять в двух СРО. Подробнее в нашей <a href=\"/legalnews/31752/\" data-link-type=\"news\">новости</a>.</p><p>Источник: Консультан.Плюс Новости&nbsp;https://www.consultant.ru/legalnews/31911/</p>", "active": true}, {"id": "news_1782724704380", "image": "uploads/landing/news_item_image_0_20260629121833_c1b44b.webp", "title": "Казначейство перечислило частые ошибки при исполнении госконтрактов в II полугодии 2025 года", "date": "2026-06-23", "text": "<div class=\"news-page__content\"><div class=\"news-page__text\"><p>Ведомство выпустило <a href=\"https://login.consultant.ru/link/?req=doc&amp;base=LAW&amp;n=537245&amp;dst=100287&amp;demo=1\" data-link-type=\"cons-doc\">обзор</a> недостатков и нарушений в финансово-бюджетной сфере. Большинство ошибок заказчики допустили при исполнении контрактов. В числе прочего они:</p><ul><li><a href=\"https://login.consultant.ru/link/?req=doc&amp;base=LAW&amp;n=537245&amp;dst=100308&amp;demo=1\" data-link-type=\"cons-doc\">не соблюдали</a> порядок оплаты товаров, работ, услуг;</li><li><a href=\"https://login.consultant.ru/link/?req=doc&amp;base=LAW&amp;n=537245&amp;dst=100313&amp;demo=1\" data-link-type=\"cons-doc\">не требовали</a> от контрагента уплатить неустойку за нарушение контракта и <a href=\"https://login.consultant.ru/link/?req=doc&amp;base=LAW&amp;n=537245&amp;dst=100314&amp;demo=1\" data-link-type=\"cons-doc\">не полностью начисляли</a> ее;</li><li><a href=\"https://login.consultant.ru/link/?req=doc&amp;base=LAW&amp;n=537245&amp;dst=100315&amp;demo=1\" data-link-type=\"cons-doc\">принимали</a> товары, работы, услуги, которые не отвечали контракту;</li><li><a href=\"https://login.consultant.ru/link/?req=doc&amp;base=LAW&amp;n=537245&amp;dst=100320&amp;demo=1\" data-link-type=\"cons-doc\">меняли</a> условия сделок без оснований для этого;</li><li><a href=\"https://login.consultant.ru/link/?req=doc&amp;base=LAW&amp;n=537245&amp;dst=100329&amp;demo=1\" data-link-type=\"cons-doc\">не использовали</a> поставленный товар.</li></ul><p>Заказчики ошибались и при определении НМЦК. Так, они <a href=\"https://login.consultant.ru/link/?req=doc&amp;base=LAW&amp;n=537245&amp;dst=100299&amp;demo=1\" data-link-type=\"cons-doc\">не соблюдали</a> требования <a href=\"https://login.consultant.ru/link/?req=doc&amp;base=LAW&amp;n=519968&amp;dst=100013&amp;demo=1\" data-link-type=\"cons-doc\">порядка</a> расчета цены, когда проводили закупки в сфере градостроительной деятельности.</p></div></div><div class=\"news-page__bottom\"><div class=\"news-page__attachments\"><div class=\"attachments attachments_docs\"><div class=\"attachments__title\">Документ:</div><div class=\"attachments__links\"><div class=\"attachments__item\"><a data-link-type=\"cons-doc\" href=\"https://login.consultant.ru/link/?req=doc&amp;base=LAW&amp;n=537245&amp;dst=100287&amp;demo=1\">Обзор недостатков и нарушений, выявленных Федеральным казначейством в финансово-бюджетной сфере за II полугодие 2025 года</a></div></div></div></div></div>", "active": true}, {"id": "news_1782724262393", "image": "uploads/landing/news_item_image_0_20260629121435_0976e6.webp", "title": "Формирование документации для госзакупки лекарств по решению врачебной комиссии: рекомендации ФАС", "date": "2026-06-22", "text": "<h1 class=\"news-page__title\"><div class=\"news-page__content\"><div class=\"news-page__intro-thumb\"></div><div class=\"news-page__text\"><p style=\"text-align: center;\"><font size=\"2\" style=\"\">В описании объекта закупки допускается указывать торговые наименования лекарств, если они назначаются пациенту по решению врачебной комиссии только <a href=\"https://login.consultant.ru/link/?req=doc&amp;base=LAW&amp;n=536992&amp;dst=100011&amp;demo=1\" data-link-type=\"cons-doc\" style=\"\">в 2 случаях</a>: индивидуальная непереносимость и жизненные показания. При этом заказчикам нужно учитывать ряд особенностей.</font></p><p style=\"text-align: center;\"><font size=\"2\">Решение врачебной комиссии о назначении и применении лекарств по торговым наименованиям нужно&nbsp;оформлять по <a href=\"https://login.consultant.ru/link/?req=doc&amp;base=LAW&amp;n=505416&amp;dst=0&amp;demo=1\" data-link-type=\"cons-doc\">Приказу N 180н</a>. Протокол комиссии <a href=\"https://login.consultant.ru/link/?req=doc&amp;base=LAW&amp;n=536992&amp;dst=100015&amp;demo=1\" data-link-type=\"cons-doc\">должен содержать</a> сведения о том, что у пациента имеется индивидуальная непереносимость взаимозаменяемых препаратов, или о том, что лекарство назначено по жизненным показаниям (с указанием обоснования такого назначения).</font></p><p style=\"text-align: center;\"><font size=\"2\">Нюансы составления протокола:</font></p><ul><li style=\"text-align: center;\"><font size=\"2\"><a href=\"https://login.consultant.ru/link/?req=doc&amp;base=LAW&amp;n=536992&amp;dst=100016&amp;demo=1\" data-link-type=\"cons-doc\">индивидуальная непереносимость</a>. В протоколе перечисляют все взаимозаменяемые препараты на дату подготовки закупочной документации;</font></li><li style=\"text-align: center;\"><font size=\"2\"><a href=\"https://login.consultant.ru/link/?req=doc&amp;base=LAW&amp;n=536992&amp;dst=100017&amp;demo=1\" data-link-type=\"cons-doc\">жизненные показания</a>. В протокол включают обоснование назначения конкретного лекарства по жизненным показаниям пациента.</font></li></ul><p style=\"text-align: center;\"><font size=\"2\">Также решение врачебной комиссии <a href=\"https://login.consultant.ru/link/?req=doc&amp;base=LAW&amp;n=536992&amp;dst=100018&amp;demo=1\" data-link-type=\"cons-doc\">нужно разместить</a> в реестре контрактов в обезличенном виде.</font></p></div></div><div class=\"news-page__bottom\"><div class=\"news-page__attachments\"><div class=\"attachments attachments_docs\"><div class=\"attachments__title\" style=\"text-align: center;\"><font size=\"2\">Документ:</font></div><div class=\"attachments__links\"><div class=\"attachments__item\" style=\"text-align: center;\"><a data-link-type=\"cons-doc\" href=\"https://login.consultant.ru/link/?req=doc&amp;base=LAW&amp;n=536992&amp;dst=100014&amp;demo=1\" style=\"\"><font size=\"2\">Письмо ФАС Росси</font></a></div></div></div></div></div><p style=\"text-align: center;\">Источник: КонсультанПлюс.Новости&nbsp;</p><span style=\"font-size: 30.4px;\"><div style=\"text-align: center;\">https://www.consultant.ru/legalnews/31851/</div></span></h1><div class=\"news-page__data\" data-published-at=\"2026-06-22T00:30:00+03:00\" data-mass=\"exotic_1\" data-type=\"news\" data-orig-scope-id=\"3\" data-original-scope-alias=\"GZ\" data-id=\"31851\" data-tags=\"Госзакупки|Закон N 44-ФЗ|Закупочная документация|Контракт (44-ФЗ)|Медицина|Медорганизации|Планирование в закупках\" data-current-feeds=\"\"><div class=\"news-page__tags\"><div class=\"animation-display animation-display_show\"><div class=\"tags-news tags-news_copy\"><div class=\"tags-news tags-news_copy__expandable clipboard__area_dblock\">  <span class=\"tags-news tags-news_copy__item clipboard__area_dinline\" data-original-scope-alias=\"GZ\"><a href=\"/legalnews/?tag_ids=914\"><span class=\"tags-news tags-news_copy__text clipboard__area_dinline\"></span></a></span></div></div></div></div></div>", "active": true}, {"id": "news_1782475094107", "image": "uploads/landing/news_item_image_1_20260629121513_7d8d29.webp", "title": "Централизованные госзакупки медизделий для больных сахарным диабетом будут проводиться с 1 июля", "date": "2026-06-18", "text": "<div class=\"news-page__intro-thumb\"></div><div class=\"news-page__text\"><p>Централизация <a href=\"https://login.consultant.ru/link/?req=doc&amp;base=LAW&amp;n=536663&amp;dst=100005&amp;demo=1\" data-link-type=\"cons-doc\">коснется</a> региональных заказчиков в части закупок медизделий по <a href=\"https://login.consultant.ru/link/?req=doc&amp;base=LAW&amp;n=536663&amp;dst=100012&amp;demo=1\" data-link-type=\"cons-doc\">спецперечню</a> за счет федеральных средств в рамках нацпроекта <a href=\"https://login.consultant.ru/link/?req=doc&amp;base=LAW&amp;n=504158&amp;dst=0&amp;demo=1\" data-link-type=\"cons-doc\">\"Продолжительная и активная жизнь\"</a>. Уполномоченным органом назначили Федеральный центр планирования и организации лекарственного обеспечения граждан при Минздраве (ФКУ \"ФЦПиЛО\" Минздрава России).</p><p>В <a href=\"https://login.consultant.ru/link/?req=doc&amp;base=LAW&amp;n=536663&amp;dst=100012&amp;demo=1\" data-link-type=\"cons-doc\">спецперечень</a> вошли:</p><ul><li>передатчик системы чрескожного мониторинга уровня глюкозы в интерстициальной жидкости;</li><li>электрод игольчатый системы чрескожного мониторинга уровня глюкозы в интерстициальной жидкости;</li><li>система чрескожного мониторинга уровня глюкозы в интерстициальной жидкости, электрохимический метод;</li><li>приемник (сканер) системы чрескожного мониторинга уровня глюкозы в интерстициальной жидкости.</li></ul><p>Речь идет о продукции с подходящими кодами по <a href=\"https://login.consultant.ru/link/?req=doc&amp;base=LAW&amp;n=511723&amp;dst=2&amp;demo=1\" data-link-type=\"cons-doc\">НКМИ</a>.</p><p>Для организации закупок заказчикам <a href=\"https://login.consultant.ru/link/?req=doc&amp;base=LAW&amp;n=536663&amp;dst=100022&amp;demo=1\" data-link-type=\"cons-doc\">потребуется направить</a> в уполномоченный орган, в частности:</p><ul><li>сведения о потребностях – до 19 июня 2026 года (далее – ежегодно не позже 1 сентября);</li><li>заявки на закупку – до 1 июля 2026 года (далее – ежегодно не позже 1 октября).</li></ul><p>Новшество <a href=\"https://login.consultant.ru/link/?req=doc&amp;base=LAW&amp;n=536663&amp;dst=100008&amp;demo=1\" data-link-type=\"cons-doc\">вступило в силу</a>. Оно применяется к закупкам медизделий, финансовое обеспечение которых предусмотрено <a href=\"https://login.consultant.ru/link/?req=doc&amp;base=LAW&amp;n=536663&amp;dst=100007&amp;demo=1\" data-link-type=\"cons-doc\">с 1 июля 2026 года</a>.</p><p><br></p><p>Источник: КонсукльтанПлюс Новости</p></div>", "active": true}, {"id": "news_1782475026267", "image": "", "title": "УФАС считает, что в госзакупках работ по паспортизации и диагностике автодорог нужны доптребования", "date": "2026-06-17", "text": "<p>Участник закупки работ по паспортизации и диагностике автодорог <a href=\"https://login.consultant.ru/link/?req=doc&amp;base=PAS&amp;n=1157492&amp;dst=100013&amp;demo=1\" data-link-type=\"cons-doc\">пожаловался</a> на то, что в извещении не установили доптребования по <a href=\"https://login.consultant.ru/link/?req=doc&amp;base=LAW&amp;n=533085&amp;dst=100131&amp;demo=1\" data-link-type=\"cons-doc\">позиции 18</a>, хотя <a href=\"https://login.consultant.ru/link/?req=doc&amp;base=LAW&amp;n=450040&amp;dst=94&amp;demo=1\" data-link-type=\"cons-doc\">классификация</a> Минтранса относит такие работы к содержанию автодорог.</p><p>Заказчик <a href=\"https://login.consultant.ru/link/?req=doc&amp;base=PAS&amp;n=1157492&amp;dst=100030&amp;demo=1\" data-link-type=\"cons-doc\">возразил</a>. Объект закупки представлял собой инженерно-обследовательские работы без физического воздействия на дорожное полотно. Характер работ не совпадал с целями введения доптребований.</p><p>УФАС <a href=\"https://login.consultant.ru/link/?req=doc&amp;base=PAS&amp;n=1157492&amp;dst=100047&amp;demo=1\" data-link-type=\"cons-doc\">признало</a> жалобу обоснованной:</p><ul><li>обследовательский характер закупаемых работ сам по себе <a href=\"https://login.consultant.ru/link/?req=doc&amp;base=PAS&amp;n=1157492&amp;dst=100041&amp;demo=1\" data-link-type=\"cons-doc\">не исключает</a> их отнесение к работам по содержанию автомобильных дорог, если это прямо следует из отраслевых норм, т.е. <a href=\"https://login.consultant.ru/link/?req=doc&amp;base=LAW&amp;n=450040&amp;dst=94&amp;demo=1\" data-link-type=\"cons-doc\">классификации</a> Минтранса;</li><li><a href=\"https://login.consultant.ru/link/?req=doc&amp;base=LAW&amp;n=533085&amp;dst=100131&amp;demo=1\" data-link-type=\"cons-doc\">позиция 18</a> доптребований применяется при закупках работ по ремонту и содержанию автодорог независимо от того, оказывается физическое воздействие на дорожное полотно либо конструктивные элементы дороги или нет.</li></ul><div>Источник: КонсультанПлюс Новости</div>", "active": true}, {"id": "news_1782457275081", "image": "uploads/landing/news_item_image_1_20260626145516_13e5a9.webp", "title": "Правительство централизовало часть закупок лекарств и медизделий с 2027 года", "date": "2026-06-16", "text": "<div class=\"news-page__intro-thumb\"></div><div class=\"news-page__text\"><p>C 2027 года закупки ряда лекарств и медизделий в рамках нацпроектов <a href=\"https://login.consultant.ru/link/?req=doc&amp;base=LAW&amp;n=504158&amp;dst=100002&amp;demo=1\" data-link-type=\"cons-doc\">\"Продолжительная и активная жизнь\"</a> и <a href=\"https://login.consultant.ru/link/?req=doc&amp;base=LAW&amp;n=501336&amp;dst=100003&amp;demo=1\" data-link-type=\"cons-doc\">\"Семья\"</a> будут централизованы. Уполномоченным органом назначили Федеральный центр планирования и организации лекарственного обеспечения граждан при Минздраве (ФКУ \"ФЦПиЛО\" Минздрава России).</p><p>Централизация <a href=\"https://login.consultant.ru/link/?req=doc&amp;base=LAW&amp;n=536664&amp;dst=100005&amp;demo=1\" data-link-type=\"cons-doc\">коснется</a>:</p><ul><li>подведомственных Минздраву федеральных казенных и бюджетных учреждений – в части закупок медизделий из <a href=\"https://login.consultant.ru/link/?req=doc&amp;base=LAW&amp;n=536664&amp;dst=100016&amp;demo=1\" data-link-type=\"cons-doc\">спецперечня</a>;</li><li>региональных заказчиков – в части закупок за счет федеральных средств медизделий из <a href=\"https://login.consultant.ru/link/?req=doc&amp;base=LAW&amp;n=536664&amp;dst=100016&amp;demo=1\" data-link-type=\"cons-doc\">спецперечня</a>, ряда лекарств для лечения сердечно-сосудистых&nbsp;заболеваний и&nbsp;противовирусных препаратов при гепатите С.</li></ul><p>Для организации закупок в следующем году заказчикам потребуется направить в уполномоченный орган, в частности:</p><ul><li>сведения о потребностях – <a href=\"https://login.consultant.ru/link/?req=doc&amp;base=LAW&amp;n=536664&amp;dst=100065&amp;demo=1\" data-link-type=\"cons-doc\">не позже 1 сентября</a>;</li><li>заявки на закупку – <a href=\"https://login.consultant.ru/link/?req=doc&amp;base=LAW&amp;n=536664&amp;dst=100066&amp;demo=1\" data-link-type=\"cons-doc\">не позже 1 октября</a>.</li></ul><p>Документ вступил в силу <a href=\"https://login.consultant.ru/link/?req=doc&amp;base=LAW&amp;n=536664&amp;dst=100012&amp;demo=1\" data-link-type=\"cons-doc\">12 июня 2026 года</a>.</p><p><br></p><p>Источник: Консультант.Плюс Новости&nbsp;https://www.consultant.ru/legalnews/31815/</p></div>", "active": true}, {"id": "news_1782456017205", "image": "uploads/landing/news_item_image_0_20260626145407_dc0d0f.webp", "title": "Национальный режим по законам N 44-ФЗ и 223-ФЗ: изменения в перечнях товаров с 1 июля 2026 года", "date": "2026-06-15", "text": "<div class=\"news-page__intro-thumb\"></div><div class=\"news-page__intro\">В перечнях продукции с запретом и ограничением появятся новые позиции. Для отдельных товаров защитная мера изменится. О том, как применять новшества и на какие сложные моменты использования защитных мер обратить внимание, расскажем в обзоре.</div><div class=\"news-page__text\"><h2><strong>Запрет закупок иностранных товаров</strong></h2><p>Рыбную продукцию <a href=\"https://login.consultant.ru/link/?req=doc&amp;base=LAW&amp;n=522103&amp;dst=100023&amp;demo=1\" data-link-type=\"cons-doc\">исключат</a> из списка&nbsp;товаров&nbsp;N&nbsp;2 с защитной мерой в виде ограничения и распространят на нее запрет. В перечне&nbsp;товаров&nbsp;N&nbsp;1 <a href=\"https://login.consultant.ru/link/?req=doc&amp;base=LAW&amp;n=522103&amp;dst=100013&amp;demo=1\" data-link-type=\"cons-doc\">появятся</a>:</p><ul><li><a href=\"https://login.consultant.ru/link/?req=doc&amp;base=LAW&amp;n=524024&amp;dst=138&amp;demo=1\" data-link-type=\"cons-doc\">10.20.1</a> - рыбная продукция (свежая, охлажденная или мороженая);</li><li><a href=\"https://login.consultant.ru/link/?req=doc&amp;base=LAW&amp;n=524024&amp;dst=141&amp;demo=1\" data-link-type=\"cons-doc\">10.20.2</a> - рыба (приготовленная или консервированная другим способом), икра и ее заменители;</li><li><a href=\"https://login.consultant.ru/link/?req=doc&amp;base=LAW&amp;n=524024&amp;dst=144&amp;demo=1\" data-link-type=\"cons-doc\">10.20.3</a> - ракообразные, моллюски и прочие беспозвоночные водные (мороженые, переработанные или консервированные).</li></ul><p>Речь идет о продукции с подходящими кодами ТН ВЭД ЕАЭС.</p><p>Участники <a href=\"https://login.consultant.ru/link/?req=doc&amp;base=LAW&amp;n=526597&amp;dst=4&amp;demo=1\" data-link-type=\"cons-doc\">будут декларировать</a> страну происхождения таких товаров в заявке, а при поставке представлять заказчику ветеринарные сопроводительные <a href=\"https://login.consultant.ru/link/?req=doc&amp;base=LAW&amp;n=524024&amp;dst=135&amp;demo=1\" data-link-type=\"cons-doc\">документы</a> (для товаров из РФ) или ветеринарные <a href=\"https://login.consultant.ru/link/?req=doc&amp;base=LAW&amp;n=524024&amp;dst=136&amp;demo=1\" data-link-type=\"cons-doc\">сертификаты</a> ЕАЭС.</p><p>Учтите, что запрет <a href=\"https://login.consultant.ru/link/?req=doc&amp;base=LAW&amp;n=497810&amp;dst=100079&amp;demo=1\" data-link-type=\"cons-doc\">нужно применять</a> как при конкурентных, так и при неконкурентных закупках, в т.ч. у единственного поставщика (подрядчика, исполнителя).</p><p><br></p><p>Источник: КонсультантПлюс. Новости&nbsp;https://www.consultant.ru/legalnews/31801/</p><p><br></p></div>", "active": true}]}, "crzrt_quiz_data": {"quizQuestions": [{"id": "q_1783198625577ryegm", "text": "уаасыафыа", "options": [{"letter": "0", "text": "[object Object]йуцкйцкйцк"}, {"letter": "1", "text": "[objйцкйцкцйкct Object]"}, {"letter": "2", "text": "[object Object]цйккйц"}, {"letter": "3", "text": "[object Object]кйцкйцкйцк"}], "correctAnswer": "1"}]}, "crzrt_bg_history": ["uploads/landing/ecp_hero_bg_1_20260707104454_8a0489.webp", "uploads/landing/ecp_hero_bg_2_20260707104613_9ef0e5.webp", "uploads/landing/ecp_hero_bg_3_20260707104613_a0c1a0.webp", "uploads/landing/ecp_hero_bg_4_20260707104614_4fcd44.webp", "uploads/landing/obuchenie_hero_bg_1_20260707105413_4ea768.webp", "uploads/landing/consulting_hero_bg_1_20260707113536_fad523.webp", "uploads/landing/consulting_hero_bg_2_20260707113536_a3114b.webp", "uploads/landing/consulting_hero_bg_3_20260707113536_4348d7.webp", "uploads/landing/support_hero_bg_1_20260707113747_44d067.webp", "uploads/landing/support_hero_bg_2_20260707113747_170692.webp", "uploads/landing/support_hero_bg_3_20260707113748_c9711c.webp", "uploads/landing/obuchenie_hero_bg_0_20260710111634_edd21a.webp", "uploads/landing/obuchenie_hero_bg_0_20260714140841_4bc925.webp", "uploads/landing/obuchenie_hero_bg_0_20260714152428_091749.webp", "uploads/landing/obuchenie_hero_bg_1_20260714152428_b27fb4.webp", "uploads/landing/obuchenie_hero_bg_2_20260714152428_f3d420.webp", "uploads/landing/obuchenie_hero_bg_3_20260714152429_e182a7.webp", "uploads/landing/obuchenie_hero_bg_0_20260714155534_c1f385.webp", "uploads/landing/obuchenie_hero_bg_1_20260714155535_d2b494.webp", "uploads/landing/obuchenie_hero_bg_2_20260714155535_41d580.webp", "uploads/landing/obuchenie_hero_bg_0_20260714155547_6afdcd.webp", "uploads/landing/obuchenie_hero_bg_1_20260714155652_62d2a4.webp", "uploads/landing/obuchenie_hero_bg_2_20260714162125_8e9310.webp", "uploads/landing/obuchenie_hero_bg_3_20260714162125_d3bc7b.webp"], "crzrt_contacts": {"phone": "8 (800) 101-78-92", "email": "info@crzrt.ru", "requisites": "АО «ЦРЗ РТ»\nИНН 1655291703\nКПП 165501001\nОГРН 1141690029800"}}
JSONDATA;
    $data = json_decode($embeddedJson, true);
}

if (!is_array($data) || empty($data)) {
    echo json_encode(['success' => false, 'error' => 'Неудачная расшифровка JSON']);
    exit;
}

$restoredKeys = [];

try {
    $stmt = $pdo->prepare("INSERT INTO settings (setting_key, setting_value) VALUES (?, ?) ON DUPLICATE KEY UPDATE setting_value = ?");
    
    foreach ($data as $key => $value) {
        $jsonStr = is_string($value) ? $value : json_encode($value, JSON_UNESCAPED_UNICODE);
        $stmt->execute([$key, $jsonStr, $jsonStr]);
        $restoredKeys[] = $key;
    }

    if (isset($data['crzrt_obuchenie_page_data']['courseRegistry'])) {
        require_once 'generate_courses.php';
        generate_static_courses($data['crzrt_obuchenie_page_data']['courseRegistry']);
    }

    echo json_encode([
        'success' => true,
        'message' => 'Все 11 наборов данных заказчика успешно восстановлены в базе данных MySQL!',
        'restored_keys' => $restoredKeys
    ], JSON_UNESCAPED_UNICODE | JSON_PRETTY_PRINT);

} catch (\PDOException $e) {
    echo json_encode(['success' => false, 'error' => 'Ошибка БД: ' . $e->getMessage()], JSON_UNESCAPED_UNICODE);
}
?>
